(self.webpackChunk=self.webpackChunk||[]).push([[288],{1206:(t,e,i)=>{"use strict";i.r(e),i.d(e,{data:()=>l});const l={key:"v-5e980d34",path:"/tools/git.html",title:"GIT",lang:"en-US",frontmatter:{title:"GIT"},excerpt:"",headers:[{level:2,title:"git常用命令",slug:"git常用命令",children:[{level:3,title:"其它",slug:"其它",children:[]},{level:3,title:"日志",slug:"日志",children:[]},{level:3,title:"版本控制",slug:"版本控制",children:[]},{level:3,title:"比较差异",slug:"比较差异",children:[]},{level:3,title:"分支操作",slug:"分支操作",children:[]},{level:3,title:"本地库跟远程库交互",slug:"本地库跟远程库交互",children:[]}]}],filePathRelative:"tools/git.md",git:{updatedTime:1626154667e3,contributors:[]}}},5566:(t,e,i)=>{"use strict";i.r(e),i.d(e,{default:()=>g});const l=(0,i(6252).uE)('<h2 id="git常用命令" tabindex="-1"><a class="header-anchor" href="#git常用命令" aria-hidden="true">#</a> git常用命令</h2><h3 id="其它" tabindex="-1"><a class="header-anchor" href="#其它" aria-hidden="true">#</a> 其它</h3><p>git init：初始化本地库</p><p>git status：查看工作区、暂存区的状态</p><p>git add <code>&lt;file name&gt;</code>：将工作区的“新建/修改”添加到暂存区</p><p>git rm --cached <code>&lt;file name&gt;</code>：移除暂存区的修改</p><p>git commit <code>&lt;file name&gt;</code>：将暂存区的内容提交到本地库</p><ul><li>tip：需要再编辑提交日志，比较麻烦，建议用下面带参数的提交方法</li></ul><p>git commit -m &quot;提交日志&quot; <code>&lt;file name&gt;</code>：文件从暂存区到本地库</p><h3 id="日志" tabindex="-1"><a class="header-anchor" href="#日志" aria-hidden="true">#</a> 日志</h3><p>git log：查看历史提交</p><ul><li>tip：空格向下翻页，b向上翻页，q退出</li></ul><p>git log --pretty=oneline：以漂亮的一行显示，包含全部哈希索引值</p><p>git log --oneline：以简洁的一行显示，包含简洁哈希索引值</p><p>git reflog：以简洁的一行显示，包含简洁哈希索引值，同时显示移动到某个历史版本所需的步数</p><p>git log --stat [-<code>&lt;number&gt;</code> 限制显示历史提交的数量] 查看修改了哪些文件</p><h3 id="版本控制" tabindex="-1"><a class="header-anchor" href="#版本控制" aria-hidden="true">#</a> 版本控制</h3><p>git reset --hard 简洁/完整哈希索引值：回到指定哈希值所对应的版本</p><p>git reset --hard HEAD：强制工作区、暂存区、本地库为当前HEAD指针所在的版本</p><p>git reset --hard HEAD^：后退一个版本</p><ul><li>tip：一个^表示回退一个版本</li></ul><p>git reset --hard HEAD~1：后退一个版本</p><ul><li>tip：波浪线~后面的数字表示后退几个版本</li></ul><h3 id="比较差异" tabindex="-1"><a class="header-anchor" href="#比较差异" aria-hidden="true">#</a> 比较差异</h3><p>git diff：比较工作区和暂存区的所有文件差异</p><p>git diff <code>&lt;file name&gt;</code>：比较工作区和暂存区的指定文件的差异</p><p>git diff HEAD|HEAD^|HEAD~|哈希索引值 <code>&lt;file name&gt;</code>：比较工作区跟本地库的某个版本的指定文件的差异</p><h3 id="分支操作" tabindex="-1"><a class="header-anchor" href="#分支操作" aria-hidden="true">#</a> 分支操作</h3><p>git branch -v：查看所有分支</p><p>git branch -d &lt;分支名&gt;：删除本地分支</p><p>git branch &lt;分支名&gt;：新建分支</p><p>git checkout &lt;分支名&gt;：切换分支</p><p>git merge &lt;被合并分支名&gt;：合并分支</p><ul><li><p>tip：如master分支合并 hot_fix分支，那么当前必须处于master分支上，然后执行 git merge hot_fix 命令</p></li><li><p>tip2：合并出现冲突</p><ol><li>删除git自动标记符号，如&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD、&gt;&gt;&gt;&gt;&gt;&gt;&gt;等</li><li>修改到满意后，保存退出</li><li>git add <code>&lt;file name&gt;</code></li><li>git commit -m &quot;日志信息&quot;，此时后面不要带文件名</li></ol></li></ul><h3 id="本地库跟远程库交互" tabindex="-1"><a class="header-anchor" href="#本地库跟远程库交互" aria-hidden="true">#</a> 本地库跟远程库交互</h3><p>git clone &lt;远程库地址&gt;：克隆远程库 功能：</p><ol><li>完整的克隆远程库为本地库</li><li>为本地库新建origin别名</li><li>初始化本地库</li></ol><p>git remote -v：查看远程库地址别名</p><p>git remote add &lt;别名&gt; &lt;远程库地址&gt;：新建远程库地址别名</p><p>git remote rm &lt;别名&gt;：删除本地中远程库别名</p><p>git push &lt;别名&gt; &lt;分支名&gt;：本地库某个分支推送到远程库，分支必须指定</p><p>git pull &lt;别名&gt; &lt;分支名&gt;：把远程库的修改拉取到本地</p><p>tip：该命令包括git fetch，git merge</p><p>git fetch &lt;远程库别名&gt; &lt;远程库分支名&gt;：抓取远程库的指定分支到本地，但没有合并</p><p>git merge &lt;远程库别名/远程库分支名&gt;：将抓取下来的远程的分支，跟当前所在分支进行合并</p><p>git fork：复制远程库</p><ul><li>tip：一般是外面团队的开发人员fork本团队项目，然后进行开发，之后外面团队发起pull request，然后本团队进行审核，如无问题本团队进行merge（合并）到团队自己的远程库，整个流程就是本团队跟外面团队的协同开发流程，Linux的团队开发成员即为这种工作方式。</li></ul>',47),g={render:function(t,e){return l}}}}]);